const crypto = require('crypto');
const secret = $env.N8N_SERVICE_SECRET;
const itemBinary = $input.item.binary;
const rawBinary = itemBinary && itemBinary.data && itemBinary.data.data;
const raw = typeof rawBinary === 'string' ? Buffer.from(rawBinary, 'base64').toString('utf8') : null;
const headers = $json.headers || {};
const received = headers['x-signature'];
if (typeof raw !== 'string' || !received) {
  return { json: { valid: false } };
}
const expected = crypto.createHmac('sha256', secret).update(raw).digest('hex');
const a = Buffer.from(expected, 'utf8');
const b = Buffer.from(received, 'utf8');
const valid = a.length === b.length && crypto.timingSafeEqual(a, b);
if (!valid) {
  return { json: { valid: false } };
}
const parsed = JSON.parse(raw);
return { json: { valid: true, tenant_id: parsed.tenant_id, phone_number_id: parsed.phone_number_id, payload: parsed.payload } };

const crypto = require('crypto');
const secret = $env.N8N_SERVICE_SECRET;
const getSignature = crypto.createHmac('sha256', secret).update('').digest('hex');
const tenantId = $json.tenant_id;
const phoneNumberId = $json.phone_number_id;
const entry = ($json.payload && $json.payload.entry) || [];
const change = (entry[0] && entry[0].changes && entry[0].changes[0]) || {};
const value = change.value || {};
const message = (value.messages || [])[0] || null;
if (!message) {
  return { json: { has_message: false, tenant_id: tenantId, get_signature: getSignature } };
}
const interactive = message.interactive || {};
const replyId = (interactive.button_reply && interactive.button_reply.id) || (interactive.list_reply && interactive.list_reply.id) || null;
let flowResponse = null;
if (interactive.nfm_reply && interactive.nfm_reply.response_json) {
  try { flowResponse = JSON.parse(interactive.nfm_reply.response_json); } catch (e) { flowResponse = null; }
}
return { json: { has_message: true, tenant_id: tenantId, phone_number_id: phoneNumberId, message_id: message.id || null, customer_whatsapp_number: message.from, message_type: message.type, text_body: (message.text && message.text.body) || null, interactive_reply_id: replyId, flow_response: flowResponse, get_signature: getSignature } };

const crypto = require('crypto');
const bodyObj = { tenant_id: $json.tenant_id, whatsapp_number: $json.customer_whatsapp_number };
const bodyStr = JSON.stringify(bodyObj);
const signature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(bodyStr).digest('hex');
return { json: { ...$json, body_str: bodyStr, signature } };

const crypto = require('crypto');
const em = $('Extract Message').item.json;
const bodyObj = { tenant_id: em.tenant_id, customer_id: $json.data.id, type: em.message_type, content: { text_body: em.text_body, interactive_reply_id: em.interactive_reply_id }, idempotency_key: em.message_id };
const bodyStr = JSON.stringify(bodyObj);
const signature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(bodyStr).digest('hex');
return { json: { body_str: bodyStr, signature: signature } };

const state = $json.data || { step: 'idle', context: '{}' };
let context = {};
try { context = typeof state.context === 'string' ? JSON.parse(state.context) : (state.context || {}); } catch (e) { context = {}; }
const em = $('Extract Message').item.json;
const replyId = em.interactive_reply_id || '';
const step = state.step || 'idle';
let route;
if (em.flow_response) route = 'flow_submitted';
else if (replyId.indexOf('confirm_') === 0) route = 'confirm';
else if (replyId.indexOf('cancel_') === 0) route = 'cancel';
else if (replyId.indexOf('reschedule_') === 0) route = 'reschedule';
else if (step === 'awaiting_service_selection' && replyId.indexOf('svc_') === 0) route = 'service_chosen';
else if (step === 'awaiting_staff_selection' && replyId.indexOf('staff_') === 0) route = 'staff_chosen';
else if (step === 'awaiting_slot_selection' && replyId.indexOf('slot_') === 0) route = 'slot_chosen';
else if (step === 'awaiting_staff_selection' && replyId === 'back_to_service') route = 'back_to_service';
else if (step === 'awaiting_slot_selection' && replyId === 'back_to_staff') route = 'back_to_staff';
else if (em.message_type === 'text' && step === 'idle') route = 'new_session';
else if (em.message_type === 'text') route = 'ai_question';
else route = 'unhandled';
return { json: { tenant_id: em.tenant_id, customer_id: $('Upsert Customer').item.json.data.id, customer_whatsapp_number: em.customer_whatsapp_number, reply_id: replyId, flow_response: em.flow_response, get_signature: em.get_signature, state_context: context, route: route } };

const crypto = require('crypto');
const dr = $('Determine Route').item.json;
const services = ($json.data || []).filter(s => s.active !== false);
const rows = services.slice(0, 10).map(s => ({ id: 'svc_' + s.id, title: String(s.name).substring(0, 24), description: (s.duration_minutes + ' dk - ' + s.price + ' TL').substring(0, 72) }));
const sendBody = { tenant_id: dr.tenant_id, type: 'interactive', customer_id: dr.customer_id, idempotency_key: dr.customer_id + '_services_' + Date.now(), interactive: { type: 'list', body: { text: '👋 Merhaba! Hangi hizmeti almak istersiniz?' }, action: { button: 'Hizmet Seç', sections: [ { title: 'Hizmetler', rows: rows } ] } } };
const sendBodyStr = JSON.stringify(sendBody);
const sendSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(sendBodyStr).digest('hex');
const stateBody = { tenant_id: dr.tenant_id, customer_id: dr.customer_id, step: 'awaiting_service_selection', context: {} };
const stateBodyStr = JSON.stringify(stateBody);
const stateSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(stateBodyStr).digest('hex');
return { json: { send_body_str: sendBodyStr, send_signature: sendSignature, state_body_str: stateBodyStr, state_signature: stateSignature } };

const crypto = require('crypto');
const dr = $('Determine Route').item.json;
const serviceId = dr.reply_id.startsWith('svc_') ? dr.reply_id.replace('svc_', '') : (dr.state_context && dr.state_context.service_id);
const staffList = ($json.data || []).filter(s => s.active !== false);
const staffIds = staffList.map(s => s.id);
const rows = staffList.slice(0, 8).map(s => ({ id: 'staff_' + s.id, title: String(s.name).substring(0, 24) }));
if (staffIds.length > 1) { rows.push({ id: 'staff_any', title: 'Farketmez' }); }
rows.push({ id: 'back_to_service', title: '◀ Geri (Hizmetler)' });
const sendBody = { tenant_id: dr.tenant_id, type: 'interactive', customer_id: dr.customer_id, idempotency_key: dr.customer_id + '_staff_' + Date.now(), interactive: { type: 'list', body: { text: '💈 Hangi ustamızdan hizmet almak istersiniz?' }, action: { button: 'Personel Seç', sections: [ { title: 'Personeller', rows: rows } ] } } };
const sendBodyStr = JSON.stringify(sendBody);
const sendSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(sendBodyStr).digest('hex');
const stateBody = { tenant_id: dr.tenant_id, customer_id: dr.customer_id, step: 'awaiting_staff_selection', context: { service_id: serviceId, staff_ids: staffIds } };
const stateBodyStr = JSON.stringify(stateBody);
const stateSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(stateBodyStr).digest('hex');
return { json: { send_body_str: sendBodyStr, send_signature: sendSignature, state_body_str: stateBodyStr, state_signature: stateSignature } };

const dr = $('Determine Route').first().json;
const ctx = dr.state_context || {};
const replyId = dr.reply_id;
let staffId;
if (replyId === 'staff_any') { staffId = (ctx.staff_ids || [])[0]; } else { staffId = replyId.replace('staff_', ''); }
const serviceId = ctx.service_id;
const dateStr = new Date().toISOString().slice(0, 10);
return [{ json: { tenant_id: dr.tenant_id, customer_id: dr.customer_id, service_id: serviceId, staff_id: staffId, date: dateStr, days: 7, get_signature: dr.get_signature, reschedule_of: null } }];

const dr = $('Determine Route').first().json;
const rest = dr.reply_id.replace('reschedule_', '');
const parts = rest.split('|');
const oldAppointmentId = parts[0];
const serviceId = parts[1];
const staffId = parts[2];
const dateStr = new Date().toISOString().slice(0, 10);
return [{ json: { tenant_id: dr.tenant_id, customer_id: dr.customer_id, service_id: serviceId, staff_id: staffId, date: dateStr, days: 7, get_signature: dr.get_signature, reschedule_of: oldAppointmentId } }];

const dr = $('Determine Route').first().json;
const sp = $('Sign: Post Appointment').first().json;
const dateStr = new Date().toISOString().slice(0, 10);
return [{ json: { tenant_id: dr.tenant_id, customer_id: dr.customer_id, service_id: sp.service_id, staff_id: sp.staff_id, date: dateStr, days: 7, get_signature: dr.get_signature, reschedule_of: sp.reschedule_of || null } }];

let req;
try { req = $('Prepare Availability Query (Staff Choice)').item.json; } catch (e) {}
if (!req) { try { req = $('Prepare Availability Query (Reschedule)').item.json; } catch (e) {} }
if (!req) { try { req = $('Slot Taken -> Retry Availability').item.json; } catch (e) {} }
return { json: { staff_id: req.staff_id, service_id: req.service_id, tenant_id: req.tenant_id, customer_id: req.customer_id, reschedule_of: req.reschedule_of, days: $json.days || {} } };

const crypto = require('crypto');
const dr = $('Determine Route').item.json;
const ctx = $json;
const days = ctx.days || {};
let allSlots = [];
for (const date of Object.keys(days).sort()) {
  for (const t of (days[date] || [])) {
    allSlots.push({ staff_id: ctx.staff_id, service_id: ctx.service_id, date, time: t });
  }
}
const top = allSlots.slice(0, 9);
const rows = top.map((s) => ({ id: 'slot_' + s.staff_id + '|' + s.service_id + '|' + s.date + 'T' + s.time, title: (s.date + ' ' + s.time).substring(0, 24), description: 'Personel: ' + s.staff_id }));
rows.push({ id: 'back_to_staff', title: '◀ Geri (Personel)' });
const rescheduleOf = ctx.reschedule_of || null;
const bodyText = top.length > 0 ? '🗓️ Sizin için uygun saatler:' : '😕 Önümüzdeki 7 günde uygun saat bulunamadı. Lütfen bizi arayın.';
const sendBody = { tenant_id: dr.tenant_id, type: 'interactive', customer_id: dr.customer_id, idempotency_key: dr.customer_id + '_slots_' + Date.now(), interactive: { type: 'list', body: { text: bodyText }, action: { button: 'Saat Seç', sections: [ { title: 'Uygun Saatler', rows: rows } ] } } };
const sendBodyStr = JSON.stringify(sendBody);
const sendSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(sendBodyStr).digest('hex');
const stateBody = { tenant_id: dr.tenant_id, customer_id: dr.customer_id, step: 'awaiting_slot_selection', context: { service_id: ctx.service_id || null, staff_id: ctx.staff_id || null, reschedule_of: rescheduleOf } };
const stateBodyStr = JSON.stringify(stateBody);
const stateSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(stateBodyStr).digest('hex');
return [{ json: { send_body_str: sendBodyStr, send_signature: sendSignature, state_body_str: stateBodyStr, state_signature: stateSignature } }];

const crypto = require('crypto');
const dr = $('Determine Route').item.json;
let staffId, serviceId, startTime, rescheduleOf;
if (dr.flow_response) {
  staffId = dr.flow_response.staff_id;
  serviceId = dr.flow_response.service_id;
  // Flow'un DatePicker/RadioButtonsGroup'u ayri 'date'/'time' alanlari doner (n8n slot_chosen'daki
  // birlesik 'HH:MM' reply id'sinden farkli); TR sabit +03:00 kurali (PHASE_17) ayni sekilde uygulanir.
  startTime = dr.flow_response.date + 'T' + dr.flow_response.time + ':00+03:00';
  rescheduleOf = dr.flow_response.reschedule_of || null;
} else {
  const rest = dr.reply_id.replace('slot_', '');
  const parts = rest.split('|');
  staffId = parts[0];
  serviceId = parts[1];
  startTime = parts[2] + ':00+03:00';
  rescheduleOf = (dr.state_context && dr.state_context.reschedule_of) || null;
}
const idempotencyKey = dr.customer_id + '_' + serviceId + '_' + startTime;
const bodyObj = { tenant_id: dr.tenant_id, staff_id: staffId, service_id: serviceId, start_time: startTime, customer_id: dr.customer_id, idempotency_key: idempotencyKey };
const bodyStr = JSON.stringify(bodyObj);
const signature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(bodyStr).digest('hex');
// Reschedule tek cagri (BACKLOG m.22): cancel+yeni yerine PATCH /appointments/{id}/reschedule
const reschedBody = rescheduleOf ? JSON.stringify({ tenant_id: dr.tenant_id, start_time: startTime }) : null;
const reschedSignature = reschedBody ? crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(reschedBody).digest('hex') : null;
return { json: { body_str: bodyStr, signature: signature, staff_id: staffId, service_id: serviceId, tenant_id: dr.tenant_id, customer_id: dr.customer_id, reschedule_of: rescheduleOf, start_time: startTime, resched_body_str: reschedBody, resched_signature: reschedSignature, get_signature: dr.get_signature } };

const crypto = require('crypto');
const sp = $('Sign: Post Appointment').item.json;
const appt = $json.data;
let sendBody, stateBody;
if (sp.reschedule_of) {
  // In-place reschedule (BACKLOG m.22): randevu ayni id ile tasindi, durum degismedi —
  // yeni onay dongusu gerekmez, bilgi mesaji + idle state yeterli.
  sendBody = { tenant_id: sp.tenant_id, type: 'text', customer_id: sp.customer_id, idempotency_key: appt.id + '_rescheduled_' + sp.start_time, text: '🔄 Randevunuz *' + sp.start_time.replace('T', ' ').slice(0, 16) + '* saatine taşındı!' };
  stateBody = { tenant_id: sp.tenant_id, customer_id: sp.customer_id, step: 'idle', context: {} };
} else {
  const buttons = [
    { type: 'reply', reply: { id: 'confirm_' + appt.id, title: '✅ Onayla' } },
    { type: 'reply', reply: { id: 'cancel_' + appt.id, title: '❌ İptal Et' } },
    { type: 'reply', reply: { id: 'reschedule_' + appt.id + '|' + sp.service_id + '|' + sp.staff_id, title: '🕐 Saat Değiştir' } },
  ];
  sendBody = { tenant_id: sp.tenant_id, type: 'interactive', customer_id: sp.customer_id, idempotency_key: appt.id + '_summary', interactive: { type: 'button', body: { text: '📅 Randevunuz oluşturuldu (beklemede). Onaylıyor musunuz?' }, action: { buttons: buttons } } };
  stateBody = { tenant_id: sp.tenant_id, customer_id: sp.customer_id, step: 'awaiting_appointment_action', context: { appointment_id: appt.id } };
}
const sendBodyStr = JSON.stringify(sendBody);
const sendSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(sendBodyStr).digest('hex');
const stateBodyStr = JSON.stringify(stateBody);
const stateSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(stateBodyStr).digest('hex');
return { json: { send_body_str: sendBodyStr, send_signature: sendSignature, state_body_str: stateBodyStr, state_signature: stateSignature, reschedule_of: sp.reschedule_of } };

const crypto = require('crypto');
const dr = $('Determine Route').item.json;
const appointmentId = dr.reply_id.replace('confirm_', '');
const bodyObj = { tenant_id: dr.tenant_id };
const bodyStr = JSON.stringify(bodyObj);
const signature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(bodyStr).digest('hex');
const stateBody = { tenant_id: dr.tenant_id, customer_id: dr.customer_id, step: 'idle', context: {} };
const stateBodyStr = JSON.stringify(stateBody);
const stateSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(stateBodyStr).digest('hex');
return { json: { appointment_id: appointmentId, body_str: bodyStr, signature: signature, state_body_str: stateBodyStr, state_signature: stateSignature, tenant_id: dr.tenant_id, customer_id: dr.customer_id } };

const crypto = require('crypto');
const sc = $('Sign: Confirm Appointment').item.json;
const appt = $json.data;
const timeRange = appt.time_range || '';
const sendBody = { tenant_id: sc.tenant_id, type: 'interactive', customer_id: sc.customer_id, idempotency_key: sc.appointment_id + '_confirmed_notice', interactive: { type: 'button', body: { text: '✅ *Randevunuz onaylandı:* ' + timeRange + '. Sizi bekliyoruz! 💈' }, action: { buttons: [ { type: 'reply', reply: { id: 'noop_confirmed', title: 'Teşekkürler' } } ] } } };
const sendBodyStr = JSON.stringify(sendBody);
const sendSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(sendBodyStr).digest('hex');
return { json: { send_body_str: sendBodyStr, send_signature: sendSignature } };

const crypto = require('crypto');
const dr = $('Determine Route').item.json;
const appointmentId = dr.reply_id.replace('cancel_', '');
const bodyObj = { tenant_id: dr.tenant_id };
const bodyStr = JSON.stringify(bodyObj);
const signature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(bodyStr).digest('hex');
const stateBody = { tenant_id: dr.tenant_id, customer_id: dr.customer_id, step: 'idle', context: {} };
const stateBodyStr = JSON.stringify(stateBody);
const stateSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(stateBodyStr).digest('hex');
