const crypto = require('crypto');
const sc = $('Sign: Cancel Appointment').item.json;
const sendBody = { tenant_id: sc.tenant_id, type: 'interactive', customer_id: sc.customer_id, idempotency_key: sc.appointment_id + '_cancelled_notice', interactive: { type: 'button', body: { text: '❌ Randevunuz iptal edildi. Tekrar görüşmek dileğiyle!' }, action: { buttons: [ { type: 'reply', reply: { id: 'noop_cancelled', title: 'Tamam' } } ] } } };
const sendBodyStr = JSON.stringify(sendBody);
const sendSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(sendBodyStr).digest('hex');
return { json: { send_body_str: sendBodyStr, send_signature: sendSignature } };

const crypto = require('crypto');
const dr = $('Determine Route').item.json;
const em = $('Extract Message').item.json;
const customerMessage = (em.text_body && String(em.text_body).trim()) || 'Musteri menu disi ya da anlasilamayan bir mesaj gonderdi.';
const bodyObj = { tenant_id: dr.tenant_id, customer_id: dr.customer_id, customer_message: customerMessage, conversation_state: dr.state_context || {} };
const bodyStr = JSON.stringify(bodyObj);
const signature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(bodyStr).digest('hex');
return { json: { body_str: bodyStr, signature: signature, tenant_id: dr.tenant_id, customer_id: dr.customer_id } };

const crypto = require('crypto');
const sa = $('Sign: AI Respond').item.json;
const resp = $json.data || {};
let reply = resp.reply || 'Su an bu mesaji otomatik yanitlayamiyorum. Lutfen menuden bir secim yaparak devam edin.';
const intent = resp.intent || 'unclear';
// 07 AI Module.md 2 adim 6: islemsel niyette musteriyi yapilandirilmis akisa yonlendir.
if (intent === 'appointment_action') { reply = reply + '\n\nRandevu islemleri icin lutfen \"randevu\" yazarak menuyu baslatabilirsiniz.'; }
const sendBody = { tenant_id: sa.tenant_id, type: 'text', customer_id: sa.customer_id, idempotency_key: sa.customer_id + '_ai_' + Date.now(), text: reply };
const sendBodyStr = JSON.stringify(sendBody);
const sendSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(sendBodyStr).digest('hex');
return { json: { send_body_str: sendBodyStr, send_signature: sendSignature, intent: intent } };

const crypto = require('crypto');
const dr = $json;
const sendBody = { tenant_id: dr.tenant_id, type: 'flow', customer_id: dr.customer_id, idempotency_key: dr.customer_id + '_flow_' + Date.now(), body_text: '💈 Randevu almak için aşağıdaki formu doldurun:', flow_data: {} };
const sendBodyStr = JSON.stringify(sendBody);
const sendSignature = crypto.createHmac('sha256', $env.N8N_SERVICE_SECRET).update(sendBodyStr).digest('hex');
return { json: { send_body_str: sendBodyStr, send_signature: sendSignature } };
